    metadata = new
    {
        endpoints = new Dictionary<string, object>
        {
            ["/content"] = new
            {
                get = new
                {
                    forwarding_required = "always",
                    authn_policies = new object[]
                    {
                        new object()
                    },
                },
            }
        },
    },
    modules = new object[]
    {
        new
        {
            name = "test.js",
            module = "TESTJS",
        }
    },
});
Response response = await client.CreateUserDefinedEndpointAsync(content);

